        LocalDateTime now = LocalDateTime.now();
        for (SpaceProbeDTO probe : spaceProbs) {
            LocalDateTime launchDate = probe.getLaunchDate();
            long yearsActive = java.time.temporal.ChronoUnit.YEARS.between(launchDate, now);
            if (yearsActive > 2) {
                activeMoreThan2Years++;
            }
        }
        System.out.println("Total space probes active for more than 2 years: " + activeMoreThan2Years);

        int lowFuelCount = 0;
        for (SpaceProbeDTO probe : spaceProbs) {
            if (probe.getFuelRemaining() < 50.0) {
                lowFuelCount++;
            }
        }
        System.out.println("Total space probes with fuelRemaining less than 50: " + lowFuelCount);

