        for (SpaceProbeDTO probe : spaceProbs) {
            if (probe.getDistanceFromEarth() <= 1000000.0) {
                withinMillionKmCount++;
            }
        }
        System.out.println("Total space probes within 1 million km of Earth: " + withinMillionKmCount);
